  agentConfig.metadata?.forEach((v, k) => init.getMetadataMap().set(k, v));
  agentConfig.arguments?.forEach((v, k) => init.getArgsMap().set(k, v));
  init.setStreammode(resolveStreamMode(agentConfig.inputOptions.channel));
